from typing import List, Dict, Any, Optional, Callable
from leann.api import SearchResult
from leann.metadata_filter import MetadataFilterEngine
from collections import defaultdict


def apply_dynamic_filters(
    search_results: List[SearchResult],
    filter_specs: Dict[str, Dict[str, Any]],
    filter_logic: str = "AND"
) -> List[SearchResult]:
    """Apply dynamic metadata filters to search results with configurable logic.

    Args:
        search_results: List of SearchResult objects to filter
        filter_specs: Dictionary of filter specifications.
            Format: {"field_name": {"operator": value}}
            Example: {"category": {"==": "tech"}, "rating": {">=": 4.0}}
        filter_logic: "AND" (all filters must match) or "OR" (any filter matches)

    Returns:
        Filtered list of SearchResult objects
    """
    if not search_results or not filter_specs:
        return search_results

    # Validate filter logic
    if filter_logic.upper() not in ["AND", "OR"]:
        raise ValueError("filter_logic must be 'AND' or 'OR'")

    # Convert SearchResult objects to dictionaries for filtering
    result_dicts = []
    result_mapping = {}  # Map dictionary representation back to original object

    for result in search_results:
        # Convert SearchResult to dictionary format
        result_dict = _convert_searchresult_to_dict(result)
        result_dicts.append(result_dict)
        result_mapping[id(result_dict)] = result

    # Create filter conditions based on the logic
    filter_conditions = []

    for field_name, operator_dict in filter_specs.items():
        if not operator_dict:
            continue

        for operator, value in operator_dict.items():
            condition = {
                "field": field_name,
                "operator": operator,
                "value": value
            }
            filter_conditions.append(condition)

    if not filter_conditions:
        return search_results

    # Apply filters using MetadataFilterEngine
    filter_engine = MetadataFilterEngine()

    # Create the main filter based on logic
    if filter_logic.upper() == "AND":
        main_filter = {"and": filter_conditions}
    else:
        main_filter = {"or": filter_conditions}

    # Apply the filter
    filtered_dicts = filter_engine.filter(result_dicts, main_filter)

    # Convert filtered dictionaries back to SearchResult objects
    filtered_results = []
    for result_dict in filtered_dicts:
        original_result = result_mapping.get(id(result_dict))
        if original_result:
            filtered_results.append(original_result)

    return filtered_results


def _convert_searchresult_to_dict(result: SearchResult) -> Dict[str, Any]:
    """Convert a SearchResult object to a dictionary for filtering.

    Args:
        result: SearchResult object to convert

    Returns:
        Dictionary representation of the result
    """
    # Extract metadata and other relevant fields from SearchResult
    result_dict = {}

    # Assuming SearchResult has a metadata attribute
    if hasattr(result, 'metadata') and result.metadata:
        result_dict.update(result.metadata)

    # Add common SearchResult attributes
    if hasattr(result, 'id'):
        result_dict['id'] = result.id
    if hasattr(result, 'score'):
        result_dict['score'] = result.score
    if hasattr(result, 'content'):
        result_dict['content'] = result.content
    if hasattr(result, 'title'):
        result_dict['title'] = result.title

    # Add any other relevant attributes dynamically
    for attr_name in dir(result):
        if not attr_name.startswith('_') and not callable(getattr(result, attr_name)):
            attr_value = getattr(result, attr_name)
            if attr_name not in result_dict and attr_name != 'metadata':
                # Skip large binary data or complex objects
                if isinstance(attr_value, (str, int, float, bool, list, dict)) or attr_value is None:
                    result_dict[attr_name] = attr_value

    return result_dict

