from typing import List, Dict, Any
from leann.api import PassageManager, LeannSearcher
from pathlib import Path
import json
from collections import Counter, defaultdict

def get_index_statistics(
    index_path: str
) -> Dict[str, Any]:
    """Get comprehensive statistics about a LEANN index.

Args:
    index_path: Path to the LEANN index file

Returns:
    Dictionary containing:
    {
        "total_passages": total number of passages,
        "metadata_fields": list of unique metadata field names,
        "field_value_counts": dictionary of field value counts
    }

Raises:
    FileNotFoundError: If index metadata file is not found"""

    # Check if index path exists
    index_dir = Path(index_path)
    if not index_dir.exists():
        raise FileNotFoundError(f"Index directory not found: {index_path}")

    # Check for metadata file (common pattern in LEANN indices)
    metadata_files = [
        index_dir / "metadata.json",
        index_dir / "index_metadata.json", 
        index_dir / "meta.json"
    ]

    metadata_file = None
    for mf in metadata_files:
        if mf.exists():
            metadata_file = mf
            break

    if metadata_file is None:
        raise FileNotFoundError(f"Index metadata file not found in: {index_path}")

    try:
        # Initialize passage manager to access index data
        manager = PassageManager(index_path)
        searcher = LeannSearcher(index_path)

        # Get total passages
        total_passages = manager.get_total_passages() if hasattr(manager, 'get_total_passages') else 0

        # Collect metadata fields and their values
        metadata_fields = set()
        field_value_counts = defaultdict(Counter)

        # Sample passages to analyze metadata (limit to reasonable number for performance)
        sample_size = min(1000, total_passages) if total_passages > 0 else 0

        for i in range(sample_size):
            try:
                passage = manager.get_passage(i)
                if hasattr(passage, 'metadata') and passage.metadata:
                    for field, value in passage.metadata.items():
                        metadata_fields.add(field)
                        field_value_counts[field][str(value)] += 1
            except (IndexError, KeyError):
                break  # Reached end of available passages

        # Convert set to sorted list for consistent output
        metadata_fields_list = sorted(list(metadata_fields))

        # Convert defaultdict to regular dict
        field_value_counts_dict = dict(field_value_counts)

        return {
            "total_passages": total_passages,
            "metadata_fields": metadata_fields_list,
            "field_value_counts": field_value_counts_dict
        }

    except Exception as e:
        # Re-raise FileNotFoundError if it's about missing files
        if "not found" in str(e).lower() or "file" in str(e).lower():
            raise FileNotFoundError(f"Error accessing index files: {e}")
        raise


def analyze_index_coverage(index_path: str, required_fields: List[str]) -> Dict[str, Any]:
    """Analyze how well an index covers required metadata fields.

Args:
    index_path: Path to the LEANN index file
    required_fields: List of metadata field names that should be present

Returns:
    Dictionary containing:
    {
        "coverage_percentage": percentage of passages that have all required fields,
        "field_coverage": dictionary mapping field name to coverage percentage,
        "missing_fields": list of required fields not found in any passage
    }

Raises:
    FileNotFoundError: If index metadata file is not found"""

    # Check if index path exists
    index_dir = Path(index_path)
    if not index_dir.exists():
        raise FileNotFoundError(f"Index directory not found: {index_path}")

    # Check for metadata file
    metadata_files = [
        index_dir / "metadata.json",
        index_dir / "index_metadata.json",
        index_dir / "meta.json"
    ]

    metadata_file = None
    for mf in metadata_files:
        if mf.exists():
            metadata_file = mf
            break

    if metadata_file is None:
        raise FileNotFoundError(f"Index metadata file not found in: {index_path}")

    try:
        # Initialize passage manager
        manager = PassageManager(index_path)

        # Get total passages
        total_passages = manager.get_total_passages() if hasattr(manager, 'get_total_passages') else 0

        if total_passages == 0:
            return {
                "coverage_percentage": 0.0,
                "field_coverage": {field: 0.0 for field in required_fields},
                "missing_fields": required_fields.copy()
            }

        # Initialize counters
        passages_with_all_fields = 0
        field_presence_count = {field: 0 for field in required_fields}

        # Analyze coverage across passages
        sample_size = min(1000, total_passages)

        for i in range(sample_size):
            try:
                passage = manager.get_passage(i)
                has_all_fields = True

                if hasattr(passage, 'metadata') and passage.metadata:
                    passage_metadata = passage.metadata

                    for field in required_fields:
                        if field in passage_metadata and passage_metadata[field] is not None:
                            field_presence_count[field] += 1
                        else:
                            has_all_fields = False

                    if has_all_fields:
                        passages_with_all_fields += 1
                else:
                    # Passage has no metadata at all
                    has_all_fields = False

            except (IndexError, KeyError):
                break  # Reached end of available passages

        # Calculate percentages
        coverage_percentage = (passages_with_all_fields / sample_size) * 100 if sample_size > 0 else 0.0
        field_coverage = {
            field: (count / sample_size) * 100 if sample_size > 0 else 0.0
            for field, count in field_presence_count.items()
        }

        # Find missing fields (fields not found in any passage)
        missing_fields = [field for field, count in field_presence_count.items() if count == 0]

        return {
            "coverage_percentage": round(coverage_percentage, 2),
            "field_coverage": {field: round(percent, 2) for field, percent in field_coverage.items()},
            "missing_fields": missing_fields
        }

    except Exception as e:
        # Re-raise FileNotFoundError if it's about missing files
        if "not found" in str(e).lower() or "file" in str(e).lower():
            raise FileNotFoundError(f"Error accessing index files: {e}")
        raise
